var freeBeerGiven = []; //['not yet', 'yes', 'withdrawn']
var freeCokeGiven = [];
var freeBeerRemoved = [];
var freeCokeRemoved = [];
var offerFreeBeverage = [];
var freeBeverageAccepted = [];
var beerNumber = [];
var cokeNumber = [];
for (var i = 0; i <= array_of_mutants.length; i++) {
  freeBeerGiven[i] = "not yet";
  freeCokeGiven[i] = "not yet";
  offerFreeBeverage[i] = false;
  freeBeverageAccepted[i] = false;
  freeBeerRemoved[i] = false;
  freeCokeRemoved[i] = false;
  beerNumber[i] = 0;
  cokeNumber[i] = 0;
}

export function init() {
  for (var i = 0; i <= array_of_mutants.length; i++) {
    freeBeerGiven[i] = "not yet";
    freeCokeGiven[i] = "not yet";
    offerFreeBeverage[i] = false;
    freeBeverageAccepted[i] = false;
    freeBeerRemoved[i] = false;
    freeCokeRemoved[i] = false;
  }
}

function pizzaPrice(frescaNumber, polloNumber) {
  return frescaNumber * 18 + polloNumber * 15;
}

export function Original(
  frescaNumber,
  polloNumber,
  beerNum,
  cokeNum,
  operation,
  i
) {
  function computePrice(
    frescaNumber,
    polloNumber,
    beerNumber,
    cokeNumber,
    freeCokeGiven,
    freeCokeRemoved,
    freeBeerGiven,
    freeBeerRemoved
  ) {
    if (freeCokeGiven === "yes" && !freeCokeRemoved)
      return (
        frescaNumber * 18 +
        polloNumber * 15 +
        beerNumber * 4 +
        (cokeNumber - 1) * 3
      );
    else if (freeBeerGiven === "yes" && !freeBeerRemoved)
      return (
        frescaNumber * 18 +
        polloNumber * 15 +
        (beerNumber - 1) * 4 +
        cokeNumber * 3
      );
    else
      return (
        frescaNumber * 18 + polloNumber * 15 + beerNumber * 4 + cokeNumber * 3
      );
  }

  var totalPrice = 0;

  beerNumber[i] = beerNum;
  cokeNumber[i] = cokeNum;
  if (operation === "clear all") {
    beerNumber[i] = 0;
    cokeNumber[i] = 0;
    offerFreeBeverage[i] = false;
    freeBeverageAccepted[i] = false;
    freeCokeGiven[i] = "not yet";
    freeBeerGiven[i] = "not yet";
    freeBeerRemoved[i] = false;
    freeCokeRemoved[i] = false;
  }
  if (operation === "add fresca" || operation === "add pollo") {
    if (pizzaPrice(frescaNumber, polloNumber) >= 45) {
      if (freeCokeGiven[i] === "withdrawn") {
        //&& !freeCokeRemoved[i]) { mutant X !!!!!!!!!!!!!!!!!!!!
        freeCokeGiven[i] = "yes";
        if (!freeCokeRemoved[i])
          if (cokeNumber[i] === 0) {
            //!!!!!!
            //mutant X
            //mutant delete it
            cokeNumber[i]++;
          } //mutant
      } else if (freeBeerGiven[i] === "withdrawn") {
        //freeCokeRemoved[i]
        freeBeerGiven[i] = "yes";
        if (!freeBeerRemoved[i])
          if (beerNumber[i] === 0) {
            beerNumber[i]++;
          } //mutant
      } else if (
        !offerFreeBeverage[i] &&
        !freeBeverageAccepted[i] && //!freeBeverageAccepted[i] delete
        (freeBeerGiven[i] !== "yes" || freeCokeGiven[i] !== "yes")
      )
        offerFreeBeverage[i] = true;
    }
  }
  if (operation === "remove fresca" || operation === "remove pollo") {
    let price = pizzaPrice(frescaNumber, polloNumber);
    if (price < 45)
      if (freeCokeGiven[i] === "yes") {
        //{
        if (!freeCokeRemoved[i]) {
          //if (!freeBeerRemoved[i]) {
          cokeNumber[i]--; //!!!!  cokeNumber--
          //  freeCokeGiven[i] = "withdrawn";
        }
        freeCokeGiven[i] = "withdrawn";
      } //}
      else if (freeBeerGiven[i] === "yes") {
        if (!freeBeerRemoved[i]) {
          beerNumber[i]--;
          // freeBeerGiven[i] = "withdrawn";
        }
        freeBeerGiven[i] = "withdrawn";
      }
  }
  if (operation === "add beer") {
    if (freeBeerRemoved[i]) {
      // if (freeBeerGiven[i] === "yes")
      freeBeerRemoved[i] = false;
    }
  }
  if (operation === "add coke") {
    if (freeCokeRemoved[i])
      // if (freeCokeGiven[i] === "yes" && freeCokeRemoved[i])
      freeCokeRemoved[i] = false;
  }
  if (operation === "remove beer") {
    if (freeBeerGiven[i] === "yes") {
      freeBeerRemoved[i] = true;
    }
  }
  if (operation === "remove coke") {
    if (freeCokeGiven[i] === "yes") freeCokeRemoved[i] = true;
  }
  if (
    operation === "free beer selected" ||
    operation === "free coke selected"
  ) {
    offerFreeBeverage[i] = false;
    freeBeverageAccepted[i] = true; //mutant
    if (operation === "free beer selected") {
      freeBeerGiven[i] = "yes";
      beerNumber[i]++;
    } else {
      freeCokeGiven[i] = "yes";
      cokeNumber[i]++;
    }
  }
  totalPrice = computePrice(
    frescaNumber,
    polloNumber,
    beerNumber[i],
    cokeNumber[i],
    freeCokeGiven[i],
    freeCokeRemoved[i],
    freeBeerGiven[i],
    freeBeerRemoved[i]
  );
  return {
    beerNum: beerNumber[i],
    cokeNum: cokeNumber[i],
    totalPrice: totalPrice,
    offerBeverage: offerFreeBeverage[i],
    beerGiven: freeBeerGiven[i],
    cokeGiven: freeCokeGiven[i],
    beerRemoved: freeBeerRemoved[i],
    cokeRemoved: freeCokeRemoved[i],
  };
}
