import React, { useState, useRef } from "react";
import "./App.css";
import { array_of_mutants, Original, init } from "./mutants";

/*
                
    Komponens(function/class)  ->  JSX elemek  -> React -> DOM(HTML)
                       A       render                          |
           state változás <-------------------esemény----------      

*/

function Grocery() {
  var [eredmeny, setEredmeny] = useState("-");
  var [killedMutants, setKilledMutants] = useState("-");
  var [testCaseNumber, setNumber] = useState(0);
  var [killed] = useState([]);
  //var [wrongTests, setWrongTests] = useState('')
  var [wrongTests] = useState([]);
  var [printWrongTests, setPrintWrongTests] = useState("");
  var [missing, setMissing] = useState("");
  var [result, setResult] = useState("");
  var [mutant] = useState([]);
  // var [wrongSolution, setWrongSolution] = useState(false);
  var [spending, setSpending] = useState("0");
  var [totalSpending, setTotalSpending] = useState(0);
  var [reducedPrice, setReducedPrice] = useState(0);
  var [reduction, setReduction] = useState(0);

  var xInput = useRef();

  for (var i = 0; i < array_of_mutants.length; i++) {
    if (killed[i] === undefined) {
      killed[i] = false;
    }
  }

  if (wrongTests[0] === undefined) wrongTests[0] = "";

  function nextTest() {
    xInput.current.value = "";

    setSpending(0);
    setTotalSpending(0);
    setEredmeny(0);
    init();
  }

  async function downloadTasks() {
    document.getElementById("downloader").click();
  }

  function tryAgain() {
    // window.location.href = '/'
    for (var i = 0; i < array_of_mutants.length; i++) {
      killed[i] = false;
    }
    nextTest();
    setNumber(0);
    setPrintWrongTests("");
    setResult("");
    setMissing("");
  }

  function callFunctions(operation) {
    //var x = +xInput.current.value;
    //console.log(x);

    //var mutantVacationDays = 0
    var killedMutants1 = "";

    var result = Original(spending, totalSpending, operation, 0);
    var totalPrice = result.totalPrice;

    setEredmeny(totalPrice); //!!!!!!!!!!!!! go to here!
    var superfluousTest = true;
    var mutantResult = {
      beerNumber: 0,
      cokeNumber: 0,
      totalPrice: 0,
      mutant: "",
    };
    testCaseNumber++;
    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        mutantResult = array_of_mutants[i](
          spending,
          totalSpending,
          operation,
          i + 1
        );
        mutant[i] = mutantResult.mutant;

        if (
          +totalPrice !== +mutantResult.totalPrice //||
        ) {
          var j = i + 1;
          killedMutants1 = killedMutants1 + j + " ";
          killed[i] = true;
          mutant[i] = "";
          superfluousTest = false;
          console.log("killed mutant: ", i + 1);
        }
      }
    }

    setKilledMutants(killedMutants1);
    setNumber(testCaseNumber);
  }

  function printResult() {
    var missingTests = false;
    var missedTestNumber = 0;

    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        missing = "Missing test: " + mutant[i]; //'Some necessary test cases are missing.'
        missingTests = true;
        missedTestNumber++;
        //   console.log('not killed ', i)
      }
    }
    var ratio =
      100 - Math.round((missedTestNumber / array_of_mutants.length) * 100);
    printWrongTests = wrongTests;
    setPrintWrongTests(printWrongTests);

    if (testCaseNumber === 0) {
      result = "Please write your test cases!";
      alert("Please write your test cases!");
      return;
    } else if (
      !missingTests //&&
      //   !wrongSolution &&
      //   testCaseNumber > optimalTestCaseNumber
    ) {
      result = "Congratulation, you are very good at test design!";
      missing = "---";
      setMissing(missing);
      //   } else if (!missingTests && testCaseNumber === optimalTestCaseNumber) {
    } else
      result =
        "You have found " + ratio + "% of the potential bugs. Try again! ";
    setResult(result);
    setMissing(missing);
  }

  return (
    <div className="App">
      <header className="Back-header">
        <p class="Back">
          <a href="https://test-design.org/practical-exercises/">
            Back to Test Design Exercises
          </a>
        </p>
      </header>

      <header className="App-header">
        {console.log("---------------------------")}
        <p class="exercise">
          {" "}
          <b> Exercise. </b> Read the specification below carefully. Insert the
          test cases one by one or create the action-state model in the{" "}
          <a href="https://cloud.harmony.ac/">Harmony tool</a>, then execute the
          test cases.
          <br /> The result will be displayed on the window of the grocery
          application.
        </p>

        <p class="specification">
          {" "}
          <div style={{ textAlign: "center", fontSize: 20 }}>
            <b> Online grocery </b>
          </div>
          In an online grocery, you have the following price reduction.
          <br />
          <b>R1</b> If you buy for at least EUR 1000 within a calendar year then
          a 5% price reduction can be claimed for the subsequent purchases in
          that calendar year.
          <br />
          <b>R2</b> When you claim price reduction, the amount you currently
          spend is not involved in the calendar year (total) spending. <br />
          <b>R3</b> If you don’t ask for price reduction then the double amount
          of the current purchase is added to your total spending. <br />
          <b>R4</b> If your total spending with corrections reaches EUR 2000,
          then an 8% reduction can be claimed and if you ask for this price
          reduction, the current amount is added to your calendar year spending.
          <br />
          <b>R5</b> If your total spending with corrections reaches EUR 3000,
          then in the subsequent calendar year your initial spending is the 25%
          of your previous year total spending (instead of zero). <br />
          <b>R6</b> The total spending with corrections is displayed when you
          enter the grocery and is not changing during your purchase. <br />
          <b>R7</b> The price to be paid for your purchase is displayed.
          &nbsp;&nbsp;{" "}
        </p>

        <p class="testcases">
          <div>
            {missing.length > 0 ? (
              <span data-harmony-id="Missing test">
                {" "}
                {missing} <br />
              </span>
            ) : (
              <span data-harmony-id="Wrong test">
                {" "}
                {wrongTests[0]} <br />
              </span>
            )}
          </div>
          <span data-harmony-id="result">{result}</span> <br />
          <br />
          Total spending:{" "}
          <span data-harmony-id="Total price">{totalSpending} </span>
          &nbsp;&nbsp;&nbsp; Buy for (EUR):{" "}
          <input size="4" data-harmony-id="Price" ref={xInput} />
          &nbsp;&nbsp;&nbsp; Price reduction:{" "}
          <span data-harmony-id="Reduction">{reduction} </span>{" "}
          &nbsp;&nbsp;&nbsp; Reduced price:{" "}
          <span data-harmony-id="Total price">{reducedPrice} </span>
          &nbsp;&nbsp;&nbsp;
          <button
            class="button"
            data-harmony-id="Claim"
            //           onClick={callFunctions("next purchase")}
          >
            {" "}
            Next purchase{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;
          <button
            class="button"
            data-harmony-id="Next year"
            //   onClick={callFunctions("next year")}
          >
            {" "}
            Next year{" "}
          </button>{" "}
          <br /> <br />
          <button class="button" data-harmony-id="Next test" onClick={nextTest}>
            {" "}
            Next test{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Stop" onClick={printResult}>
            {" "}
            Show my result{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Try again" onClick={tryAgain}>
            {" "}
            Try again{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          {/*
          <button
            class="download"
            data-harmony-id="Download"
            onClick={downloadTasks}
          >
            {" "}
            Download templates{" "}
          </button>{" "}
          <a
            id="downloader"
            href="../templates/pizza_templates.zip"
            download
            hidden
          ></a>
          */}
          <br />
        </p>
      </header>
    </div>
  );
}

export default Grocery;
